const resultados = [];

for (const item of $input.all()) {
  const d = item.json;

  // ─── Identificação ────────────────────────────────────────────────
  const identificacao = {
    id:         d.id,
    shortCode:  d.shortCode,
    tipo:       d.type,
    url:        d.url,
    inputUrl:   d.inputUrl,
  };

  // ─── Dono / Conta ─────────────────────────────────────────────────
  const conta = {
    username:     d.ownerUsername,
    nomeCompleto: d.ownerFullName,
    ownerId:      d.ownerId,
  };

  // ─── Métricas ─────────────────────────────────────────────────────
  const metricas = {
    curtidas:        d.likesCount,
    visualizacoes:   d.videoViewCount,
    reproducoes:     d.videoPlayCount,
    comentarios:     d.commentsCount,
    duracaoSegundos: d.videoDuration,
    engajamento:     d.likesCount && d.videoViewCount
      ? ((d.likesCount / d.videoViewCount) * 100).toFixed(2) + "%"
      : null,
  };

  // ─── Conteúdo / Caption ───────────────────────────────────────────
  const conteudo = {
    caption:    d.caption,
    hashtags:   d.hashtags,
    mencoes:    d.mentions,
    localizacao: d.locationName,
    localizacaoId: d.locationId,
    isPinned:   d.isPinned,
    publicadoEm: d.timestamp,
  };

  // ─── Mídia ────────────────────────────────────────────────────────
  const midia = {
    thumbnail:      d.displayUrl,
    videoUrl:       d.videoUrl,
    audioUrl:       d.audioUrl,
    videoDownload:  d.downloadedVideo,
    largura:        d.dimensionsWidth,
    productType:    d.productType,
  };

  // ─── Música ───────────────────────────────────────────────────────
  const musica = d.musicInfo ? {
    artista:          d.musicInfo.artist_name,
    nomeFaixa:        d.musicInfo.song_name,
    audioOriginal:    d.musicInfo.uses_original_audio,
    audioId:          d.musicInfo.audio_id,
  } : null;

  // ─── Comentários ──────────────────────────────────────────────────
  const comentarios = {
    total:          d.commentsCount,
    desativados:    d.isCommentsDisabled,
    primeiroComent: d.firstComment,
    ultimos:        (d.latestComments || []).map(c => ({
      usuario: c.ownerUsername,
      texto:   c.text,
    })),
  };

  resultados.push({
    json: {
      identificacao,
      conta,
      metricas,
      conteudo,
      midia,
      musica,
      comentarios,
    }
  });
}

return resultados;

// ─── Normaliza \\n literal em quebra real ────────────────────────────
function normalizarTexto(text) {
  return text.replace(/\\n/g, '\n');
}

// ─── Divide por separador --- e extrai bloco pelo label ──────────────
function extrairSecao(text, label) {
  const blocos = text.split(/\n---\n/);
  for (const bloco of blocos) {
    if (bloco.includes(label)) {
      // Remove a linha do título (primeira linha com **...**)
      const linhas = bloco.trim().split('\n');
      const semTitulo = linhas.slice(1).join('\n').trim();
      return semTitulo || null;
    }
  }
  return null;
}

// ─── Extrai sub-campos (- **Label:** valor) ──────────────────────────
function extrairSubCampo(text, label) {
  const escapedLabel = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp(`\\*\\*${escapedLabel}:\\*\\*\\s*(.+)`);
  const match = text.match(regex);
  return match ? match[1].trim() : null;
}

const resultados = [];

for (const item of $input.all()) {
  const texto = normalizarTexto(item.json.content.parts[0].text);

  // ─── Debug ───────────────────────────────────────────────────────
  console.log("BLOCOS:", texto.split(/\n---\n/).map((b, i) => `[${i}] ${b.substring(0, 80)}`));

  // ─── Seções principais ───────────────────────────────────────────
  const gancho        = extrairSecao(texto, "HOOK");
  const analiseGancho = extrairSecao(texto, "HOOK ANALYSIS");
  const roteiro       = extrairSecao(texto, "FULL SCRIPT");
  const estrutura     = extrairSecao(texto, "NARRATIVE STRUCTURE");
  const porque        = extrairSecao(texto, "WHY IT WORKED");
  const adaptacao     = extrairSecao(texto, "HOW TO ADAPT THIS FORMAT TO YOUR NICHE");

  // ─── Sub-campos da análise do gancho ─────────────────────────────
  const ganchoTipo     = analiseGancho ? extrairSubCampo(analiseGancho, "Type") : null;
  const ganchoGatilho  = analiseGancho ? extrairSubCampo(analiseGancho, "Trigger") : null;
  const ganchoForca    = analiseGancho ? extrairSubCampo(analiseGancho, "Strength") : null;
  const ganchoRetencao = analiseGancho ? extrairSubCampo(analiseGancho, "What keeps them watching") : null;

  // ─── Sub-campos da adaptação ─────────────────────────────────────
  const esqueleto      = adaptacao ? extrairSubCampo(adaptacao, "Replicable skeleton") : null;
  const troque         = adaptacao ? extrairSubCampo(adaptacao, "Swap this") : null;
  const ganchoAdaptado = adaptacao ? extrairSubCampo(adaptacao, "Adapted hook") : null;
  const cuidado        = adaptacao ? extrairSubCampo(adaptacao, "Watch out for") : null;

  // ─── Divide roteiro em pontos (cenas) ────────────────────────────
  const pontos = [];
  if (roteiro) {
    const roteiroRegex = /([^()]+?)(\([^)]+\))/g;
    let match;
    while ((match = roteiroRegex.exec(roteiro)) !== null) {
      const narracao = match[1].trim().replace(/^\s*[.,]+/, "").trim();
      const cena     = match[2].replace(/[()]/g, "").trim();
      if (narracao) pontos.push({ narracao, cena });
    }
  }

  resultados.push({
    json: {
      gancho,
      analise_gancho: {
        tipo:     ganchoTipo,
        gatilho:  ganchoGatilho,
        forca:    ganchoForca,
        retencao: ganchoRetencao,
      },
      roteiro_completo:  roteiro,
      roteiro_em_pontos: pontos,
      estrutura,
      porque_funcionou:  porque,
      adaptacao: {
        esqueleto,
        troque,
        gancho_adaptado: ganchoAdaptado,
        cuidado,
      },
    }
  });
}

return resultados;
